package com.user.servlet; import com.DB.DBConnect; import com.DAO.*; import com.entity.*; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*;
@WebServlet("/cart") public class CartServlet extends HttpServlet {protected void doGet(HttpServletRequest r,HttpServletResponse p)throws IOException{HttpSession s=r.getSession();try(var c=DBConnect.getConn()){int bid=Integer.parseInt(r.getParameter("bid")),uid=Integer.parseInt(r.getParameter("uid"));BookDtls b=new BookDAOImpl(c).getBookById(bid);Cart x=new Cart();x.setBid(bid);x.setUid(uid);x.setBookName(b.getBookname());x.setAuthor(b.getAuthor());x.setPrice(Double.valueOf(b.getPrice()));s.setAttribute(new CartDAOImpl(c).addCart(x)?"addCart":"failedMsg","Book Added to cart");}catch(Exception e){s.setAttribute("failedMsg",e.getMessage());}String ref=r.getHeader("Referer");p.sendRedirect(ref!=null?ref:"index.jsp");}}
